#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int P;
        scanf("%d", &P);
        if (P == 3) {
            printf("Case %d: 1-sum\n", i + 1);
        } else if (P == 7 || P == 13) {
            printf("Case %d: 3-altersum\n", i + 1);
        } else if (P == 11) {
            printf("Case %d: 1-altersum\n", i + 1);
        }
    }
    return 0;
}

