code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int P = sc.nextInt();
            if (P == 3) {
                System.out.println("Case " + (i + 1) + ": 1-sum");
            } else if (P == 7 || P == 13) {
                System.out.println("Case " + (i + 1) + ": 3-altersum");
            } else if (P == 11) {
                System.out.println("Case " + (i + 1) + ": 1-altersum");
            }
        }
    }
}

